function report = runSyntheticPinholePhaseA(options)
%RUNSYNTHETICPINHOLEPHASEA Render and validate the Phase A baseline.
%
% The images are independently rendered from a continuous world-plane
% texture. PinholePlaneOracle supplies analytic truth without calling
% HeightSweepGeometry. All reported geometry uses one-based [x,y] pixels,
% local ENU metres, and SYNTHETIC_LOCAL_Z elevation metres.
%
% Traceability: algorithm description Secs. 5.1-5.5, 10.2, 10.5, 11.4,
% and 14.1-14.2; Eqs. (52)-(58) and Algorithm 1 through raw cost curves.

arguments
    options.ConfigFile (1, 1) string = ""
    options.Display (1, 1) logical = true
end

root = fileparts(fileparts(mfilename("fullpath")));
src = fullfile(root, "src");
oldPath = path;
addpath(src);
cleanup = onCleanup(@() path(oldPath));
if strlength(options.ConfigFile) == 0
    options.ConfigFile = fullfile(root, "config", "synthetic", ...
        "pinhole_horizontal_55deg_v1.json");
end

renderer = SyntheticPinholeRenderer.fromJson(options.ConfigFile);
geom = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);

timer = tic;
pair = renderer.renderPair;
renderSeconds = toc(timer);

[x, y] = meshgrid(1:renderer.ImageSize(2), 1:renderer.ImageSize(1));
p = [x(:), y(:)];
[wt, vt, it] = PinholePlaneOracle.correspondence( ...
    renderer.ReferenceCamera, renderer.MovingCamera, p, ...
    renderer.TrueHeightMetres);
[tt, kt, vkt] = PinholePlaneOracle.heightDerivative( ...
    renderer.ReferenceCamera, renderer.MovingCamera, p, ...
    renderer.TrueHeightMetres);
[sx, sy, sg, vsg] = PinholePlaneOracle.localSampling( ...
    renderer.ReferenceCamera, p, renderer.TrueHeightMetres);
[wg, vg, ig] = geom.warp(p, renderer.TrueHeightMetres);
both = vt & vg;
epe = vecnorm(wg - wt, 2, 2);
maxEpe = max(epe(both), [], "omitmissing");
falseValidRate = nnz(ig & ~it) / numel(it);
falseInvalidRate = nnz(~ig & it) / numel(it);

pc = phaseASamplePixels(renderer.ImageSize);
[ta, ka, vka] = PinholePlaneOracle.heightDerivative( ...
    renderer.ReferenceCamera, renderer.MovingCamera, pc, ...
    renderer.TrueHeightMetres);
labelStep = renderer.TargetMotionPerLabelPixels ...
    / median(ka(vka));
z = phaseAHeightLabels(renderer.SearchRangeMetres, labelStep);
levels = 2 ^ renderer.BitDepth - 1;
curve = HeightCostCurve(geom, ...
    double(pair.ReferenceImage) ./ levels, ...
    double(pair.MovingImage) ./ levels, ...
    DerivativeSigma=1, IntegrationSigma=2, ...
    ReferenceValid=pair.ReferenceValid, MovingValid=pair.MovingValid);
timer = tic;
cost = curve.evaluate(pc, z, MinimumSupportFraction=0.95);
costSeconds = toc(timer);
costMetrics = HeightCostMetrics.analyze(cost, ...
    repmat(renderer.TrueHeightMetres, size(pc, 1), 1));

[t1, ~, vd1] = geom.heightDerivative( ...
    pc, renderer.TrueHeightMetres, DeltaHeight=1);
[th, ~, vdh] = geom.heightDerivative( ...
    pc, renderer.TrueHeightMetres, DeltaHeight=0.5);
derivativeError1 = max(abs(t1 - ta), [], "all", "omitmissing");
derivativeErrorHalf = max(abs(th - ta), [], "all", "omitmissing");

truth = struct( ...
    "MovingX", reshape(wt(:, 1), renderer.ImageSize), ...
    "MovingY", reshape(wt(:, 2), renderer.ImageSize), ...
    "DisplacementX", reshape(wt(:, 1) - p(:, 1), renderer.ImageSize), ...
    "DisplacementY", reshape(wt(:, 2) - p(:, 2), renderer.ImageSize), ...
    "HeightDerivativeX", reshape(tt(:, 1), renderer.ImageSize), ...
    "HeightDerivativeY", reshape(tt(:, 2), renderer.ImageSize), ...
    "ObservabilityPixelsPerMetre", reshape(kt, renderer.ImageSize), ...
    "ReferenceSamplingXMetresPerPixel", ...
    reshape(sx, renderer.ImageSize), ...
    "ReferenceSamplingYMetresPerPixel", ...
    reshape(sy, renderer.ImageSize), ...
    "ReferenceSamplingGeometricMeanMetresPerPixel", ...
    reshape(sg, renderer.ImageSize), ...
    "GeometricValid", reshape(vt, renderer.ImageSize), ...
    "InsideMovingImage", reshape(it, renderer.ImageSize));
metrics = struct( ...
    "MaximumOracleWarpErrorPixels", maxEpe, ...
    "FalseValidRate", falseValidRate, ...
    "FalseInvalidRate", falseInvalidRate, ...
    "ReferenceSamplingXMetresPerPixel", phaseAStats(sx, vsg), ...
    "ReferenceSamplingYMetresPerPixel", phaseAStats(sy, vsg), ...
    "ReferenceSamplingGeometricMeanMetresPerPixel", ...
    phaseAStats(sg, vsg), ...
    "ObservabilityPixelsPerMetre", phaseAStats(kt, vkt), ...
    "DerivativeErrorDelta1", derivativeError1, ...
    "DerivativeErrorDeltaHalf", derivativeErrorHalf, ...
    "DerivativeValid", vd1 & vdh & vka);
configuration = struct( ...
    "Identifier", renderer.Identifier, ...
    "ConfigFile", options.ConfigFile, ...
    "ImageSize", renderer.ImageSize, ...
    "BitDepth", renderer.BitDepth, ...
    "HorizontalFieldOfViewDegrees", ...
    renderer.HorizontalFieldOfViewDegrees, ...
    "CenterGsdMetres", renderer.CenterGsdMetres, ...
    "MeanObliquityDegrees", renderer.MeanObliquityDegrees, ...
    "ConvergenceDegrees", renderer.ConvergenceDegrees, ...
    "SlantRangeMetres", renderer.SlantRangeMetres, ...
    "TrueHeightMetres", renderer.TrueHeightMetres, ...
    "SearchRangeMetres", renderer.SearchRangeMetres, ...
    "HeightLabelStepMetres", labelStep);
report = struct( ...
    "Configuration", configuration, ...
    "ReferenceImage", pair.ReferenceImage, ...
    "MovingImage", pair.MovingImage, ...
    "ReferenceValid", pair.ReferenceValid, ...
    "MovingValid", pair.MovingValid, ...
    "Truth", truth, ...
    "Metrics", metrics, ...
    "SamplePixels", pc, ...
    "HeightLabelsMetres", z, ...
    "CostCurve", cost, ...
    "CostMetrics", costMetrics, ...
    "SelectedHeight", cost.SelectedHeight, ...
    "RenderSeconds", renderSeconds, ...
    "CostSeconds", costSeconds);

fprintf("Phase A synthetic pinhole baseline: %s\n", renderer.Identifier);
fprintf("  Image: %d x %d, uint16 with %d meaningful bits\n", ...
    renderer.ImageSize(1), renderer.ImageSize(2), renderer.BitDepth);
fprintf("  HFOV %.3f deg, obliquity %.1f deg, convergence %.1f deg\n", ...
    renderer.HorizontalFieldOfViewDegrees, ...
    renderer.MeanObliquityDegrees, renderer.ConvergenceDegrees);
fprintf("  Slant range: %.3f m\n", renderer.SlantRangeMetres);
fprintf("  Center-target GSD: %.3f m/pixel; measured median: %.6f\n", ...
    renderer.CenterGsdMetres, metrics. ...
    ReferenceSamplingGeometricMeanMetresPerPixel.Median);
fprintf("  Observability median: %.6f pixels/m\n", ...
    metrics.ObservabilityPixelsPerMetre.Median);
fprintf("  Height labels: %d at %.6f m (about %.3f pixels/label)\n", ...
    numel(z), labelStep, renderer.TargetMotionPerLabelPixels);
fprintf("  Oracle/geometry max EPE: %.3e pixels\n", maxEpe);
fprintf("  False-valid %.3e; false-invalid %.3e\n", ...
    falseValidRate, falseInvalidRate);
fprintf("  dw/dZ max error: %.3e (1 m), %.3e (0.5 m)\n", ...
    derivativeError1, derivativeErrorHalf);
fprintf("  Selected heights at center " + ...
    "[ZNCC Census NGF point-spin2 T0 T1 T2 T3 T4 hybrid]: " + ...
    "[%.3f %.3f %.3f %.3f %.3f %.3f %.3f %.3f %.3f %.3f] m\n", ...
    cost.SelectedHeight.Zncc(3), ...
    cost.SelectedHeight.Census(3), ...
    cost.SelectedHeight.NormalizedGradient(3), ...
    cost.SelectedHeight.PointSpin2(3), ...
    cost.SelectedHeight.Spin2T0(3), ...
    cost.SelectedHeight.Spin2T1(3), ...
    cost.SelectedHeight.Spin2T2(3), ...
    cost.SelectedHeight.Spin2T3(3), ...
    cost.SelectedHeight.Spin2T4(3), ...
    cost.SelectedHeight.HybridZnccSpin2T3(3));
fprintf("  Runtime: render %.3f s, sparse costs %.3f s\n", ...
    renderSeconds, costSeconds);
names = fieldnames(costMetrics);
fprintf("  Center raw-curve metrics " + ...
    "[error_m rank ties percentile margin curvature]:\n");
for k = 1:numel(names)
    m = costMetrics.(names{k});
    fprintf("    %-18s [% .3f %.0f %.0f %.1f %.3g %.3g]\n", names{k}, ...
        m.SelectedHeightErrorMetres(3), m.TruthLabelRank(3), ...
        m.TruthCostTieCount(3), m.TruthCostPercentile(3), ...
        m.DistinctMinimumMargin(3), ...
        m.SelectedCurvaturePerMetreSquared(3));
end

if options.Display
    phaseAShowImages(report);
    phaseAShowCosts(report);
end

clear cleanup
end

function p = phaseASamplePixels(imageSize)
cx = (imageSize(2) + 1) / 2;
cy = (imageSize(1) + 1) / 2;
d = 0.18 .* [imageSize(2), imageSize(1)];
p = [cx - d(1), cy; cx, cy - d(2); cx, cy; ...
    cx, cy + d(2); cx + d(1), cy];
end

function z = phaseAHeightLabels(range, step)
n0 = floor(abs(range(1)) / step);
n1 = floor(abs(range(2)) / step);
z = (-n0:n1) .* step;
end

function s = phaseAStats(x, valid)
v = x(valid & isfinite(x));
s = struct("Minimum", min(v), "Median", median(v), "Maximum", max(v));
end

function phaseAShowImages(report)
fig = uifigure(Name="Phase A synthetic pinhole diagnostic", ...
    Position=[80, 80, 1200, 820]);
grid = uigridlayout(fig, [2, 2]);
mode = string(report.Configuration.BitDepth) + "-bit";

v1 = viewer2d(grid);
title(v1, "Reference uint16 image");
imageshow(report.ReferenceImage, Parent=v1, DisplayRangeMode=mode);

v2 = viewer2d(grid);
title(v2, "Moving uint16 image");
imageshow(report.MovingImage, Parent=v2, DisplayRangeMode=mode);

v3 = viewer2d(grid);
title(v3, "Truth displacement X (pixels)");
imageshow(report.Truth.DisplacementX, Parent=v3, ...
    DisplayRangeMode="data-range");

v4 = viewer2d(grid);
title(v4, "Observability (pixels/metre)");
imageshow(report.Truth.ObservabilityPixelsPerMetre, Parent=v4, ...
    DisplayRangeMode="data-range");
end

function phaseAShowCosts(report)
figure(Name="Phase A unregularized height costs");
tiledlayout(4, 3);
names = ["Zncc", "Census", "NormalizedGradient", "PointSpin2", ...
    "Spin2T0", "Spin2T1", "Spin2T2", "Spin2T3", "Spin2T4", ...
    "HybridZnccSpin2T3"];
labels = ["ZNCC", "Census", "Normalized gradient", "Point spin-2", ...
    "T0 scalar q_2", "T1 polar rotation", "T2 conformal factor", ...
    "T3 transported q_2", "T4 transported q_2 + slope", ...
    "ZNCC + confidence-weighted T3"];
for k = 1:numel(names)
    nexttile;
    plot(report.HeightLabelsMetres, ...
        report.CostCurve.Costs.(names(k))(3, :), "-o", LineWidth=1.1);
    xline(report.Configuration.TrueHeightMetres, "--k", "Truth");
    grid on;
    xlabel("Elevation Z (m)");
    ylabel("Unregularized cost");
    title(labels(k));
end
nexttile([1, 2]);
hold on;
compare = ["Spin2T0", "Spin2T1", "Spin2T2", "Spin2T3", ...
    "Spin2T4", "HybridZnccSpin2T3"];
for k = 1:numel(compare)
    plot(report.HeightLabelsMetres, ...
        report.CostCurve.Costs.(compare(k))(3, :), LineWidth=1.1);
end
xline(report.Configuration.TrueHeightMetres, "--k", "Truth");
grid on;
xlabel("Elevation Z (m)");
ylabel("Unregularized cost");
title("Center transport comparison");
legend(compare, Location="best");
end
